// Brand Site logo data — sourced from assets/logos.manifest.json, which is
// generated by `npm run build:logos` from logos.config.ts. The Foundations page
// builds its picker + gallery entirely from this; nothing is hand-curated.
//   Edit logos.config.ts → npm run build:logos → this updates automatically.
// Read with fs (not require) so a long-running `eleventy --serve` picks up a
// regenerated manifest instead of serving Node's cached require().
const fs = require("fs");
const path = require("path");
const manifest = JSON.parse(
  fs.readFileSync(path.join(__dirname, "..", "..", "assets", "logos.manifest.json"), "utf8"),
);

// Ordered, de-duplicated axis values (order = first appearance in the manifest).
function axis(key, labelKey) {
  const seen = new Map();
  for (const v of manifest) {
    if (!seen.has(v[key])) seen.set(v[key], { key: v[key], label: v[labelKey] });
  }
  return [...seen.values()];
}

const marks = axis("mark", "markLabel");
const surfaces = axis("surface", "surfaceLabel");
const frames = axis("frame", "frameLabel");

// Sensible hero default for the picker.
const fallback = manifest[0];
const def =
  manifest.find((v) => v.mark === "inline" && v.surface === "dark" && v.frame === "margin") ||
  fallback;

module.exports = {
  variants: manifest,
  marks,
  surfaces,
  frames,
  count: manifest.length,
  default: def ? def.name : null,
};
